#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                printf("%d", A[i / 2]);
            } else {
                printf(" %d", A[N - 1 - (i / 2)]);
            }
        }
        printf("\n");
    }
    return 0;
}

