    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        int A[N];
        for (int i = 0; i < N; i++) {
            cin >> A[i];
        }
        sort(A, A + N);
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                cout << A[i / 2] << ' ';
            } else {
                cout << A[N - 1 - (i / 2)] << ' ';
            }
        }
        cout << endl;
    }
    return 0;
}

code.Java:
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            for (int i = 0; i < N; i++) {
                if (i % 2 == 0) {
                    System.out.print(A[i / 2] + " ");
                } else {
                    System.out.print(A[N - 1 - (i / 2)] + " ");
                }
            }
            System.out.println();
        }
    }
}

