const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    A.sort((a, b) => a - b);
    for (let j = 0; j < N; j++) {
        if (j % 2 == 0) {
            process.stdout.write(A[Math.floor(j / 2)] + ' ');
        } else {
            process.stdout.write(A[N - 1 - Math.floor(j / 2)] + ' ');
        }
    }
    console.log();
}

